+//! ANTHROPIC_API_KEY=sk-ant-... VCR_MODE=record \
+//!   cargo test provider_streaming::anthropic_
+//! ```
+//!
+//! Playback (default in CI):
+//! ```bash
+//! VCR_MODE=playback VCR_CASSETTE_DIR=tests/fixtures/vcr \
+//!   cargo test provider_streaming::anthropic_
+//! ```
