+    match mode {
+        VcrMode::Record => env::var("AZURE_OPENAI_API_KEY")
+            .expect("AZURE_OPENAI_API_KEY required for VCR record mode"),
+        _ => env::var("AZURE_OPENAI_API_KEY").unwrap_or_else(|_| "test-key".to_string()),
+    }
+}
