+            let message = err.to_string();
+            let needle = format!("HTTP {}", expectation.status);
+            assert!(
+                message.contains(&needle),
+                "expected error to contain '{needle}', got '{message}'"
+            );
+            if let Some(fragment) = expectation.contains {
+                assert!(
+                    message.contains(fragment),
